        external.run(server_transport).await.unwrap();
    });

    // Create main server with proxy
    let main = ServerBuilder::new("main", "1.0")
        .as_proxy("ext", client_transport)
        .await
        .unwrap()
        .build();

    // List tools should include proxied tools
    let tools = main.list_tools().await.unwrap();
    assert!(tools.tools.iter().any(|t| t.name == "ext/echo"));
    assert!(tools.tools.iter().any(|t| t.name == "ext/add"));
