+/// Generates an API key.
+#[must_use]
+pub fn generate_api_key() -> String {
+    generate_test_token("sk-test", 24)
+}
+
+/// Generates a session token.
+#[must_use]
+pub fn generate_session_token() -> String {
+    generate_test_token("session", 16)
+}
